package com.example.prototype;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Patterns;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private ProgressBar progressBar;
    private AuthRepository authRepository;
    private SessionManager sessionManager;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        Button loginButton = findViewById(R.id.loginButton);
        progressBar = findViewById(R.id.progressBar);

        authRepository = new AuthRepository();
        sessionManager = new SessionManager(this);

        if (sessionManager.isLoggedIn()) {
            openHome();
            finish();
            return;
        }

        String savedEmail = sessionManager.getEmail();
        if (!TextUtils.isEmpty(savedEmail)) {
            emailInput.setText(savedEmail);
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString();

        if (!isValidEmail(email)) {
            emailInput.setError("Enter a valid email");
            emailInput.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Enter password");
            passwordInput.requestFocus();
            return;
        }

        setLoading(true);

        authRepository.login(email, password, new AuthRepository.LoginCallback() {
            @Override
            public void onSuccess(String token) {
                runOnUiThread(() -> {
                    setLoading(false);
                    sessionManager.saveSession(email, token);
                    Toast.makeText(LoginActivity.this, "Login successful", Toast.LENGTH_SHORT).show();
                    openHome();
                    finish();
                });
            }

            @Override
            public void onError(String message) {
                runOnUiThread(() -> {
                    setLoading(false);
                    Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
                });
            }
        });
    }

    private boolean isValidEmail(String email) {
        return !TextUtils.isEmpty(email) && Patterns.EMAIL_ADDRESS.matcher(email).matches();
    }

    private void setLoading(boolean loading) {
        progressBar.setVisibility(loading ? View.VISIBLE : View.GONE);
    }

    private void openHome() {
        startActivity(new Intent(this, HomeActivity.class));
    }
}

package com.example.prototype;

import android.content.Context;
import android.content.SharedPreferences;

public class SessionManager {

    private static final String PREF_NAME = "prototype_session";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_AUTH_TOKEN = "key_auth_token";

    private final SharedPreferences preferences;

    public SessionManager(Context context) {
        this.preferences = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
    }

    public void saveSession(String email, String authToken) {
        preferences.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .apply();
    }

    public boolean isLoggedIn() {
        String token = preferences.getString(KEY_AUTH_TOKEN, null);
        return token != null && !token.isEmpty();
    }

    public String getEmail() {
        return preferences.getString(KEY_EMAIL, "");
    }

    public String getAuthToken() {
        return preferences.getString(KEY_AUTH_TOKEN, "");
    }

    public void clearSession() {
        preferences.edit().clear().apply();
    }
}

package com.example.prototype;

import android.os.Handler;
import android.os.Looper;

public class AuthRepository {

    public interface LoginCallback {
        void onSuccess(String token);
        void onError(String message);
    }

    public void login(String email, String password, LoginCallback callback) {
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            if ("demo@example.com".equalsIgnoreCase(email) && "password123".equals(password)) {
                callback.onSuccess("demo_auth_token_123456");
            } else {
                callback.onError("Invalid credentials");
            }
        }, 1200);
    }
}

package com.example.prototype;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private SessionManager sessionManager;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        sessionManager = new SessionManager(this);

        TextView welcomeText = findViewById(R.id.welcomeText);
        Button logoutButton = findViewById(R.id.logoutButton);

        String email = sessionManager.getEmail();
        String token = sessionManager.getAuthToken();

        welcomeText.setText("Welcome " + email + "\nToken: " + token);

        logoutButton.setOnClickListener(v -> {
            sessionManager.clearSession();
            Intent intent = new Intent(HomeActivity.this, LoginActivity.class);
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
            startActivity(intent);
            finish();
        });
    }
}

